// And groups predicates with the AND operator between them.
func And(predicates ...predicate.CommissionSplitLog) predicate.CommissionSplitLog {
	return predicate.CommissionSplitLog(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.CommissionSplitLog) predicate.CommissionSplitLog {
	return predicate.CommissionSplitLog(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.CommissionSplitLog) predicate.CommissionSplitLog {
	return predicate.CommissionSplitLog(sql.NotPredicates(p))
}
